// Active nav on scroll
const sections = document.querySelectorAll('section[id]');
const navLinks = document.querySelectorAll('.nav-links a');
window.addEventListener('scroll', () => {
  let cur = '';
  sections.forEach(s => { if (window.scrollY >= s.offsetTop - 90) cur = s.id; });
  navLinks.forEach(a => a.classList.toggle('active', a.getAttribute('href') === '#' + cur));
}, { passive: true });

// Download CV — downloads the actual PDF
function downloadCV() {
  const b64 = "";
  const bytes = atob(b64);
  const arr = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
  const blob = new Blob([arr], { type: 'application/pdf' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'Sai_Sandeep_Durgasi_CV.pdf';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// Formspree contact form
const contactForm = document.getElementById('contactForm');
if (contactForm) {
  contactForm.addEventListener('submit', async function(e) {
    e.preventDefault();
    const btn = document.getElementById('submitBtn');
    const btnText = document.getElementById('btnText');
    const msg = document.getElementById('formMsg');

    // Loading state
    btn.disabled = true;
    btnText.textContent = 'Sending...';

    try {
      const res = await fetch('https://formspree.io/f/xkoqvpkq', {
        method: 'POST',
        headers: { 'Accept': 'application/json' },
        body: new FormData(contactForm)
      });

      if (res.ok) {
        msg.style.display = 'block';
        msg.style.background = 'rgba(255,107,53,0.15)';
        msg.style.border = '1px solid rgba(255,107,53,0.4)';
        msg.style.color = '#FF9A3C';
        msg.textContent = '✅ Message sent! Sandeep will get back to you soon.';
        contactForm.reset();
        btnText.textContent = 'Message Sent!';
      } else {
        throw new Error('Failed');
      }
    } catch {
      msg.style.display = 'block';
      msg.style.background = 'rgba(255,60,60,0.1)';
      msg.style.border = '1px solid rgba(255,60,60,0.3)';
      msg.style.color = '#ff6b6b';
      msg.textContent = '❌ Something went wrong. Please email directly: sandeepsai2508@gmail.com';
      btnText.textContent = 'Send Message';
      btn.disabled = false;
    }
  });
}

// ── THEME TOGGLE ──────────────────────────────
function toggleTheme() {
  const isLight = document.body.classList.toggle('light-mode');
  document.getElementById('themeIcon').textContent  = isLight ? '☀️' : '🌙';
  document.getElementById('themeLabel').textContent = isLight ? 'Light' : 'Dark';
  localStorage.setItem('theme', isLight ? 'light' : 'dark');
}
// restore saved theme on load
(function() {
  if (localStorage.getItem('theme') === 'light') {
    document.body.classList.add('light-mode');
    const icon  = document.getElementById('themeIcon');
    const label = document.getElementById('themeLabel');
    if (icon)  icon.textContent  = '☀️';
    if (label) label.textContent = 'Light';
  }
})();
